var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드, 혼자 너무 앞서가면 안 돼. 어둠 속에 뭐가 있을지 몰라.","JPN":"シェパード、あまり一人で先に行っちゃ駄目だ。暗闇の中には何があるかわからないから。","ENG":"Shepherd, don't go too far out alone. There might be something in the dark.","TWN":"牧羊犬，別太往前。你永遠不知道黑暗中會有什麼。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"괜찮아요. 어두워도 잘 보여요.","JPN":"大丈夫。暗くてもちゃんと見えるよ。","ENG":"It's okay. Shepherd can see well in the dark.","TWN":"沒關係。牧羊犬在黑暗中也能看得見。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그리고 더 빨리 가야…","JPN":"それに、もっと早く行かないと……","ENG":"And we have to hurry–","TWN":"還能走得更快……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…앗.","JPN":"……あっ。","ENG":"...Ouch.","TWN":"……啊。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"조심해. 앞을 보고 가야지.","JPN":"気をつけて。前を向いて行かないと。","ENG":"Be careful. Look ahead as you go.","TWN":"小心點啊……走路看著前面。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괜찮니? 세게 부딪히는 소리가 났는데.","JPN":"大丈夫？　強くぶつけた音がしたけど。","ENG":"Are you okay? It sounded like you bumped into it pretty hard.","TWN":"沒事吧？剛剛好大一聲。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…응. 셰퍼드 튼튼해서 괜찮아요.","JPN":"……うん。シェパードは頑丈だから、平気。","ENG":"...Yeah. It's okay. Because Shepherd is strong.","TWN":"……牧羊犬很強壯的，沒關係。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런 길 한복판에 나무가 자라 있다니… 정말 별일이네.","JPN":"こんな道の真ん中に木が生えてるなんて……本当に珍しい。","ENG":"I can't believe there's a tree just growing in the middle of the path like that... How strange.","TWN":"路中間竟然會有一棵這樣的樹……真不尋常。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드가 다니는 길 주변엔 식물 자라요.","JPN":"シェパードが通る道の周りには、植物が生えるの。","ENG":"Wherever Shepherd goes, plants grow nearby.","TWN":"牧羊犬走過的路都會長上植物。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"바닥에도 벽에도 자라서 어른들이 불편하다고 했어요.","JPN":"床にも壁にも生えてきて、大人たちが面倒だって言ってた。","ENG":"But the adults said that it was an inconvenience because they grew on the floors and walls.","TWN":"大人們說這樣很不方便，因為地板上和牆上也都是植物。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"식물이 자라는 게… 네가 있어서 그런 거라고?","JPN":"あなたがいるから……植物が生える？","ENG":"The plants are growing... because of you?","TWN":"長出植物……是因為你嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 셰퍼드가 집에 오래 머무르면 식물도 더 많이 자라요.","JPN":"うん、シェパードが長居すれば、植物ももっとたくさん生えてくるの。","ENG":"Uh-huh. If Shepherd stays at home for long, plants grow even more.","TWN":"嗯，牧羊犬待在家裡的時間越長，植物就會長得越多。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하늘도 햇볕도 없지만, 봄에는 더 무럭무럭 자라고요.","JPN":"空も日光もないけど、春にはもっともっと生えるよ。","ENG":"Even though there is no sky and sunlight, they grow faster in spring.","TWN":"即使沒有天空和陽光。而且春天會長得更加旺盛。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"게다가, 계절마다 자라나는 식물도 다르거든요.","JPN":"それに、季節によって生える植物も違うんだ。","ENG":"Also, different plants grow depending on the season.","TWN":"每個季節，生長的植物也不同。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"계절이라니. 이면세계에 그런 게 존재할 리가…","JPN":"季節って。裏世界にそんなもの存在するわけ……","ENG":"Season? But those don't exist in the Counterside...","TWN":"季節？在異界怎麼可能存在這些……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…찾았다.","JPN":"……見つけた。","ENG":"…Found it.","TWN":"……找到了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이거 먹어요. 어른들도 좋아했어요.","JPN":"これ食べて。大人たちも好きだった。","ENG":"Eat this. Adults like it.","TWN":"請吃吧。大人們都喜歡這個的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이건 포도잖아? 아니, 머루인가…?","JPN":"これは、ブドウ？　いや、ヤマブドウか……？","ENG":"This is a grape? No, is it a wild grape...?","TWN":"這些是葡萄嗎？不對，是山葡萄嗎……？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이름은 몰라요. 여름 끝무렵에 여기서 자라요.","JPN":"名前は知らない。夏の終わりにここから生えるの。","ENG":"Shepherd doesn't know the name. But they grow at the end of summer.","TWN":"牧羊犬不知道它的名字。但是夏天快結束的時候它就會長出來。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"관심 안 주면 금방 시들어서 자주 와서 보살폈어요.","JPN":"世話しないとすぐ枯れちゃうから、よく見てたんだ。","ENG":"They also wither away if unattended, so Shepherd came here often to take care of them.","TWN":"一不注意很快就會枯萎了，所以牧羊犬經常過來照顧它。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"네가 열매를 맺게 했다고?","JPN":"あなたが実らせた？","ENG":"You helped it bear fruit?","TWN":"你讓它結出了果實？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응.","JPN":"うん。","ENG":"Uh-huh.","TWN":"嗯、嗯。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"배고프면 마음 모양이 길쭉해져요. 당신처럼.","JPN":"お腹空いたら心の形が細長くなるの。あなたのように。","ENG":"People's heart shapes become long when they're hungry. Just like yours.","TWN":"人類肚子餓的時候，心的形狀就會變長。就像現在的史賓瑟一樣。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 항상 배가 고팠는데, 그래서 항상 화가 난 걸지도 몰라요.","JPN":"ラッチャーはいつもお腹を空かせてたけど、それでいつも怒ってたのかもしれないよ。","ENG":"Lurcher is always hungry. Maybe that's why he's always violent.","TWN":"而獵犬總是很餓，這可能就是它總是發火的原因。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"난폭해지기 전에 얼른 먹어요. 얼른.","JPN":"乱暴になるまえに、早く食べて。早く。","ENG":"You should eat before you get violent. Hurry.","TWN":"在變得暴力之前請快點吃掉吧。快點快點。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그, 그러니…?","JPN":"そ、そう……？","ENG":"I-is that so...?","TWN":"是、是嗎……？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"저렇게 눈을 반짝이는 건 처음 보네.","JPN":"あんなに目がキラキラしてるのは初めて見た。","ENG":"I've never seen her eyes twinkle like that before.","TWN":"第一次看到她的眼睛那麼亮。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식지대긴 하지만… 뭐, 이제 와서 딱히 조심할 것도 없겠지.","JPN":"侵食地帯だけど……まあ、今さら気をつける必要もないか。","ENG":"This might be a Corrupted Area... but I guess there's nothing to be careful about now.","TWN":"雖然是侵蝕地區……但現在也沒什麼可小心的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"음? 달아.","JPN":"あれっ？　甘い。","ENG":"Hmm? It's sweet.","TWN":"嗯？甜的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"제법 먹을 만하잖아?","JPN":"結構いけるね。","ENG":"This is pretty good.","TWN":"不錯吃呢。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"잘됐다.","JPN":"よかった。","ENG":"That's good.","TWN":"太好了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드는 맛 모르니까, 조금 걱정했어요.","JPN":"シェパードは味がわからないから、ちょっと心配してたの。","ENG":"Shepherd can't taste. So Shepherd was a little worried.","TWN":"牧羊犬嚐不出味道，本來還有點擔心。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다시 돌아왔어.","JPN":"また戻って来た。","ENG":"We're back.","TWN":"回來了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"괴물에게 쫓길 때 떨어졌던 그 나무야.","JPN":"化け物に追われていた時に落ちたあの木よ。","ENG":"This is the tree we fell on top of when that monster was chasing us.","TWN":"這是被怪物追趕時摔下來的樹。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…기억나요.","JPN":"……覚えてる。","ENG":"...Shepherd remembers.","TWN":"……牧羊犬想起來了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"여기서 얼음 자주 먹었어요.","JPN":"ここでよく氷を食べてたよ。","ENG":"Shepherd used to eat ice here often.","TWN":"牧羊犬經常在這裡吃冰塊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"실험 끝나면 날 아끼는 사람이 데려와서 시원하게 해줬어요.","JPN":"実験が終わると、シェパードを大切に思っている人が連れてきて、涼ませてくれた。","ENG":"Whenever an experiment was done, the person dear to Shepherd brought Shepherd here and helped Shepherd cool down.","TWN":"實驗結束後，有一個在乎牧羊犬的人送來給我降溫。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"얼음… 좋아하는구나.","JPN":"氷……好きなんだね。","ENG":"You... really like ice.","TWN":"牧羊犬……真的很喜歡冰塊啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 맛은 모르지만 시원한 거 좋아해.","JPN":"うん、味はわからないけど、冷たいの好き。","ENG":"Uh-huh. Shepherd can't taste, but Shepherd likes refreshing things.","TWN":"嗯、嗯，雖然牧羊犬嚐不出味道，但喜歡冰涼涼的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이렇게 큰 나무가 자란 걸 보면, 참 자주 왔던 모양이네.","JPN":"こんなに木が大きく育っているのを見ると、本当によく来ていたようだな。","ENG":"Seeing how tall this tree is, you must've come here quite a lot.","TWN":"你一定經常來這裡吧，這棵樹都長這麼大了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드랑 날 아끼는 사람 말곤 아무도 여길 안 찾아요.","JPN":"シェパードと、シェパードを大切に思っている人以外は誰もここに来ないの。","ENG":"Only Shepherd and the person dear to Shepherd come here.","TWN":"除了牧羊犬和在乎牧羊犬的人，就沒有人來這裡了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그래서 그 사람이 잠깐 떠났을 때도, 여기에 숨어있었어.","JPN":"それであの人がちょっと留守だった時にも、ここに隠れてたよ。","ENG":"That's why when he left, Shepherd hid here.","TWN":"所以，即使在那個人離開的時候，牧羊犬也會躲在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"5년… 아마도 그 정도의 시간이었겠지.","JPN":"5年……多分、そのくらいの時間だったはずだ。","ENG":"Five years... That's how long it's probably been.","TWN":"五年……大概有那麼久了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"혼자서 기다리느라 정말 외로웠겠네.","JPN":"一人で待ってて、本当に寂しくなかったか？","ENG":"You must've been lonely waiting here all alone.","TWN":"獨自等待的滋味一定很難受吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"괜찮아요. 잠자고 있었으니까.","JPN":"大丈夫。眠っていたから。","ENG":"It's okay. Shepherd was sleeping.","TWN":"沒關係。因為牧羊犬一直在睡覺。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"어.","JPN":"あっ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그러고보니, 그때도 어떤 꿈을 꿨어요.","JPN":"そういえば、あの時にも何か夢を見たの。","ENG":"Come to think of it, Shepherd had a dream that time too.","TWN":"現在想想，牧羊犬當時也做過一個夢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그런데… 잘 기억이 안 나.","JPN":"でも……よく思い出せない。","ENG":"But... Shepherd can't remember.","TWN":"但是……有些不太記得了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"너무 신경 쓰지 마. 나도 아침에 일어나보면 기억을 하나씩 잃어버리곤 하니까.","JPN":"大丈夫よ。私も朝起きたら、一つずつ記憶を失ってるから。","ENG":"Don't worry. I also forget stuff when I wake up in the morning.","TWN":"沒事的。我早上睡醒的時候，也會忘記很多事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"요즘은… 너무 중요한 것도 잊어버려서 문제지만.","JPN":"最近は……とても重要なことも忘れちゃって問題なんだけど。","ENG":"The problem for me is that... I forget the important stuff nowadays.","TWN":"雖然……最近忘記了一些非常重要的事情有些麻煩。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신의 색… 갑자기 슬퍼졌어요.","JPN":"あなたの色……いきなり悲しくなったよ。","ENG":"Your color... It suddenly became sad.","TWN":"史賓瑟的顏色……突然變得悲傷起來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"미안. 셰퍼드 때문일 거예요. 말실수 자주 하거든요.","JPN":"ごめん。多分シェパードのせい。よく変なこと言っちゃうから。","ENG":"Sorry. It's because of Shepherd, isn't it? Because Shepherd makes a lot of mistakes.","TWN":"對不起。都是因為牧羊犬。牧羊犬經常說錯話。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아니. 너 때문이 아니야.","JPN":"いや。あなたのせいじゃない。","ENG":"No, it's not your fault.","TWN":"不。不是因為你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"후후… 셰퍼드는 감정을 볼 줄 아니까, 함부로 숨기질 못하겠네.","JPN":"ふふ……シェパードは感情を見ることができるから、むやみに隠し事なんてできないな。","ENG":"Haha... since you can see emotion, I guess I can't hide it in front of you, Shepherd.","TWN":"呵呵……看來在牧羊犬面前，是瞞不住情緒的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"마음 숨기고 싶어요? 셰퍼드가 눈 감으면 돼요.","JPN":"心、隠したい？　シェパードが目をつむればいいの。","ENG":"Do you want to hide it? Then Shepherd can just close Shepherd's eyes.","TWN":"你不想讓人看到嗎？牧羊犬可以閉上眼睛。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 무리는 하지 마. 또 나무에 부딪힐라.","JPN":"そんなに無理しないで。また木にぶつかるよ。","ENG":"You don't have to do that. You might bump into a tree again.","TWN":"不要做那樣的蠢事情。又會撞樹上的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그리고, 굳이 숨기고 싶은 게 아니야.","JPN":"それに、別に隠したいわけでもないから。","ENG":"And, it's not that I want to hide it.","TWN":"而且，我沒有想隱藏。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"어쩌면 숨기는 데 익숙해져 있던 걸지도 모르지.","JPN":"もしかしたら、隠すことに慣れていたのかもしれない。","ENG":"Maybe I've just gotten used to hiding my feelings.","TWN":"或許，我只是習慣了隱藏。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래서 조금 후회도 돼. 함께 있을 때 좀 더 숨김 없이 표현할 걸.","JPN":"だから少し後悔している。一緒にいた時に、隠さずにもっと表現すればよかった。","ENG":"I regret it a little. I should've expressed them more when I had the chance.","TWN":"我有些後悔了。早知道就應該更加坦誠一點。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이렇게 될 줄 알았으면… 그때 더 많이 사랑한다고 해 둘 걸.","JPN":"こんなことになるなら……あの時に愛してるってもっとたくさん伝えておけばよかった。","ENG":"If I knew this was going to happen... then I would've said that I loved you more back then.","TWN":"如果早知道事情會變成這樣……那時，就應該多表達下愛意。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 후회 말이야.","JPN":"そんな後悔を。","ENG":"You know, these kinds of regrets.","TWN":"你看到了吧，那種遺憾的顏色。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"역시… 닮았어요.","JPN":"やっぱり……似てる。","ENG":"You... really are similar.","TWN":"果然……你們很像。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"응…? 닮다니? 뭐가?","JPN":"うん……？　似てる？　何が？","ENG":"Hmm...? Similar? To what?","TWN":"嗯……？像？像什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"날 아끼는 사람도 그런 웃는 표정으로, 많이 슬퍼했거든요.","JPN":"シェパードを大切に思ってる人も、そんな笑顔でとても悲しんでた。","ENG":"The person dear to Shepherd also smiled like that when he was sad.","TWN":"在乎牧羊犬的人，還有史賓瑟，你們哪怕笑著，心裡也很難過。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체들에게 둘러싸인 날 도와준 것도… 혹시 그 사람과 비슷한 걸 느꼈기 때문이야?","JPN":"侵食体に囲まれた私を助けてくれたのも……もしかして、あの人と似たようなものが感じたから？","ENG":"The time you helped me when I was surrounded by C.O.s... did you do that because you felt something similar to that person from me?","TWN":"我被侵蝕體包圍時，你來幫助我……也是因為我們很像嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 맞아요.","JPN":"うん、そうだよ。","ENG":"Yes, that's right.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그치만 사람들 눈에 안 띄기로 약속했으니까, 도망쳤어요.","JPN":"でも、人の目につかないって約束したから、逃げたの。","ENG":"But Shepherd promised not to be seen by other people, so Shepherd ran.","TWN":"但是牧羊犬約定好了，不能被人發現，於是就逃跑了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"거기엔 무서운 마음을 가진 사람도 있었고요.","JPN":"そこには怖い心を持ってる人もいたし。","ENG":"Also there was someone with a scary heart too.","TWN":"而且，那裡有個人的心很可怕。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"무서운 마음이라고…?","JPN":"怖い心……？","ENG":"Scary heart...?","TWN":"心很可怕……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"무슨 일이지?","JPN":"何事だ？","ENG":"What's going on?","TWN":"發生什麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};